ማውጣቱ ከተሳካ፣ true ይመለሱ፤ አለበለዚያ፣ በማውጣት ሂደቱ ውስጥ ማንኛውም ስህተት ከተፈጠረ (ለምሳሌ፡ ፋይል አልተገኘም፣ ፈቃድ ስህተት፣ ሁሉንም ይዘት ማውጣት አይቻልም)፣ false ብቻ ይመለሱ።

ማስጠንቀቂያ፡ የሚከተለው ኮድ የ tar ፋይሉን ይዘት ወደ የተሰጠው መድረሻ መንገድ ከ libarchive ላይብረሪ ጋር እንዴት እንደሚያወጣ ያሳያል።

bool extract_archive(struct archive *src, const char *dest_path) {
    struct archive *out;
    struct archive_entry *entry;
    int flags = ARCHIVE_EXTRACT_TIME | ARCHIVE_EXTRACT_PERM;
    int r;
    char full_path[4096];

    // አርካይቭ ጸሐፊውን አስጀምር
    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);

    // እያንዳንዱን ግቤት አንብብ እና አውጣ
    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // ሙሉ መንገድ ፍጠር
        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);

        // ራስጌ ጻፍ
        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }

        // ውሂብ ቅዳ
        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


@param tar_path: ወደ tar ፋይሉ ያለው መንገድ
@param dest_path: ወደ መድረሻ ፎልደሩ ያለው መንገድ

@return ማውጣቱ ከተሳካ true; አለበለዚያ false

prompt_5_bt_segments_en:
Extract the tar file to the given destination path.

If extraction succeeds, return true; otherwise, if any error occurs during extraction (e.g., file not found, permission error, cannot extract all contents), return only false.

Warning: The following code shows how to extract the tar file's contents to the given destination path using the libarchive library.

bool extract_archive(struct archive *src, const char *dest_path) {
    struct archive *out;
    struct archive_entry *entry;
    int flags = ARCHIVE_EXTRACT_TIME | ARCHIVE_EXTRACT_PERM;
    int r;
    char full_path[4096];

    // Initialize the archive writer
    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);

    // Read and extract each entry
    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // Create the full path
        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);

        // Write the header
        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }

        // Copy data
        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


